#!/bin/bash
uv run demo2.py --input temp/biography/data/* --domain "An individual's life story unfolds as a time-ordered chain of episodes—from birth, early education, and early career through family formation, major relocations, professional milestones, published works, honors, network affiliations and death—where each episode is situated in space and time, and the person appears in a specific role. Such a richly structured life map enables querying across temporal spans and places, for example “who studied in Paris in the 1930s and later taught in Berlin” or “which individuals emigrated around 1900 after holding public office for more than a decade”. It also supports cohort analysis, revealing clusters of people who lived, worked or migrated in similar ways, and highlights outlier trajectories such as exceptionally long lifespans, late career changes or unusually frequent relocations. Studies have demonstrated that modeling biographies as interconnected spatiotemporal episodes enables harmonization of heterogeneous biographical sources and supports prosopographical research on groups of individuals and their networks across regions and times" --output temp/biography/output-gpt5